module RefModule (dout, din, addr, clk, we);
   input [3:0] addr;
   input [3:0] din;
   input clk, we;
   output [3:0] dout;

   reg [3:0] mem [15:0];
   reg [3:0] dout;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
      if (we)
         mem[addr] <= din;
   end

   always @(*) begin
      dout = mem[addr];
   end

endmodule
